// Strict payload validation — rules brief contract.
// Required: story_id, video_url, video_type ∈ {object_talking, food_discovery}.
const body = $input.first().json.body || $input.first().json || {};

const errors = [];
if (!body.story_id)  errors.push("missing 'story_id'");
if (!body.video_url) errors.push("missing 'video_url'");
const ALLOWED = ['object_talking', 'food_discovery'];
if (!ALLOWED.includes(body.video_type)) errors.push("invalid 'video_type' (got " + JSON.stringify(body.video_type) + "; expected one of " + ALLOWED.join('|') + ")");

if (errors.length) {
  throw new Error('Payload validation failed: ' + errors.join('; '));
}

return [{ json: { body, validated: true } }];

// Build a single Telegram message combining all 4 Redis lookups
const objCnt   = $('LLEN script:object_talking').first().json.result;
const objPub   = $('LRANGE publish:object_talking').first().json.result || [];
const foodCnt  = $('LLEN script:food_discovery').first().json.result;
const foodPub  = $('LRANGE publish:food_discovery').first().json.result || [];

const title = (s) => {
  try {
    const o = JSON.parse(s);
    return o.captionText || o.videoUrl || '<no title>';
  } catch { return String(s).slice(0, 80); }
};
const fmt = (arr) => arr.length
  ? arr.map((s, i) => `  ${i + 1}. ${title(s)}`).join('\n')
  : '  _none_';

const message =
`\ud83d\udcca *Queue Status*

\ud83c\udfac *object_talking*
\u2022 Scripts queued: ${objCnt ?? 0}
\u2022 Publish-ready (${objPub.length}):
${fmt(objPub)}

\ud83c\udf72 *food_discovery*
\u2022 Scripts queued: ${foodCnt ?? 0}
\u2022 Publish-ready (${foodPub.length}):
${fmt(foodPub)}`;

return [{ json: { message } }];
